(function(window, document) {
  const dirTick = BlogDirection === 'rtl' ? false : true;

  function IsCodiTicker(selector, options) {
    const elements = typeof selector === "string" 
      ? document.querySelectorAll(selector) 
      : selector;
    
    if (!elements || elements.length === 0) {
      console.warn("IsCodiTicker: لم يتم العثور على عناصر");
      return false;
    }
    
    const defaults = {
      anim_duration: 200,
      reverse_elm: false,
      force_loop: false,
      start_paused: false
    };
    
    this.config = Object.assign({}, defaults, options || {});
    this.elements = elements;
    this.initialized = false;
    
    this.init();
    return this;
  }

  IsCodiTicker.prototype = {
    init: function() {
      if (this.initialized) return;
      
      const elementsArray = Array.from(this.elements);
      for (let i = 0; i < elementsArray.length; i++) {
        const wrapper = elementsArray[i];
        const ul = wrapper.querySelector("ul");
        if (!ul) continue;
        
        if (wrapper.classList.contains("iscoditkr-initialized")) {
          this.destroy(wrapper);
        }
        
        const listItems = Array.from(ul.children);
        const containerWidth = ul.parentElement.offsetWidth;
        const halfContainerWidth = containerWidth / 2;
        
        const tempStyles = document.createElement('style');
        tempStyles.textContent = `
          .iscoditkr-measure { margin: 0; padding: 0; list-style: none; }
          .iscoditkr-measure > li { display: inline-block; }
        `;
        document.head.appendChild(tempStyles);
        
        ul.classList.add('iscoditkr-measure');
        const listWidth = ul.offsetWidth;
        ul.classList.remove('iscoditkr-measure');
        document.head.removeChild(tempStyles);
        
        wrapper.classList.add("iscoditkr-wrapper");
        
        const setupConveyor = () => {
          for (let j = 0; j < listItems.length; j++) {
            const clone = listItems[j].cloneNode(true);
            clone.classList.add("clone");
            ul.appendChild(clone);
          }
          
          let totalWidth = 0;
          const children = Array.from(ul.children);
          for (let j = 0; j < children.length; j++) {
            totalWidth += children[j].offsetWidth;
          }
          
          ul.style.width = `${totalWidth}px`;
          
          const pauseHandler = () => this.pauseAnim(ul);
          const resumeHandler = () => {
            this.pauseAnim(ul);
            this.conveyorAnimate(ul, dirTick ? "reverse" : "normal");
          };
          
          wrapper.addEventListener("pointerenter", pauseHandler);
          wrapper.addEventListener("pointerleave", resumeHandler);
          
          if (this.config.reverse_elm) {
            const previousElement = wrapper.previousElementSibling;
            if (previousElement && previousElement.classList.contains("iscoditkr-label")) {
              const reverseHandler = () => {
                this.pauseAnim(ul);
                this.conveyorAnimate(ul, dirTick ? "normal" : "reverse");
              };
              
              previousElement.addEventListener("pointerenter", reverseHandler);
              previousElement.addEventListener("pointerleave", resumeHandler);
              
              previousElement.addEventListener("click", e => {
                e.preventDefault();
                return false;
              });
            }
          }
          
          this.conveyorAnimate(ul, dirTick ? "reverse" : "normal");
        };
        
        if (listWidth >= halfContainerWidth) {
          setupConveyor();
        } 
        else if (this.config.force_loop) {
          const addClonesUntilFit = () => {
            let currentWidth = ul.scrollWidth;
            let targetWidth = ul.parentElement.offsetWidth;
            
            while (currentWidth < targetWidth || currentWidth < halfContainerWidth) {
              const originalItems = Array.from(ul.querySelectorAll(':not(.clone)'));
              if (originalItems.length === 0) break;
              
              for (let j = 0; j < originalItems.length; j++) {
                const clone = originalItems[j].cloneNode(true);
                clone.classList.add("clone");
                ul.appendChild(clone);
              }
              
              currentWidth = ul.scrollWidth;
            }
            
            return currentWidth >= halfContainerWidth;
          };
          
          if (addClonesUntilFit()) {
            setupConveyor();
          }
        }
        
        wrapper.classList.add("iscoditkr-initialized");
      }
      
      if (this.config.start_paused) {
        const elementsArray = Array.from(this.elements);
        for (let i = 0; i < elementsArray.length; i++) {
          const ul = elementsArray[i].querySelector("ul");
          if (ul) this.pauseAnim(ul);
        }
      }
      
      this.initialized = true;
    },
    
    destroy: function(wrapper) {
      if (!wrapper) {
        const elementsArray = Array.from(this.elements);
        for (let i = 0; i < elementsArray.length; i++) {
          this.destroy(elementsArray[i]);
        }
        return;
      }
      
      const ul = wrapper.querySelector("ul");
      if (!ul) return;
      
      this.pauseAnim(ul);
      
      const newWrapper = wrapper.cloneNode(true);
      wrapper.parentNode.replaceChild(newWrapper, wrapper);
      
      newWrapper.classList.remove("iscoditkr-wrapper", "iscoditkr-initialized");
      
      const newUl = newWrapper.querySelector("ul");
      const clones = Array.from(newUl.querySelectorAll(".clone"));
      for (let i = 0; i < clones.length; i++) {
        newUl.removeChild(clones[i]);
      }
      
      newUl.removeAttribute("style");
    },
    
    conveyorAnimate: function(ul, direction) {
      if (!ul || !ul.parentNode) return;
      
      const self = this;
      let targetPos;
      const listWidth = ul.offsetWidth;
      const currentLeft = parseFloat(ul.style.left || "0");
      
      let operator = "-";
      let newDirection = "normal";
      
      if (direction === "reverse") {
        targetPos = listWidth / 2;
        
        if (currentLeft > 0) {
          ul.style.left = `-${targetPos}px`;
          self.conveyorAnimate(ul, "reverse");
          return;
        }
        
        operator = "+";
        newDirection = "reverse";
      } else {
        targetPos = -(listWidth / 2);
        
        if (currentLeft < targetPos) {
          const offset = -1 * (targetPos - currentLeft);
          ul.style.left = `${offset}px`;
          self.conveyorAnimate(ul, newDirection);
          return;
        }
      }
      
      let start = null;
      const duration = this.config.anim_duration;
      const pixelsPerFrame = 10;
      
      function step(timestamp) {
        if (!start) start = timestamp;
        
        const elapsed = timestamp - start;
        const progress = Math.min(elapsed / duration, 1);
        
        let newPos = currentLeft;
        if (operator === "-") {
          newPos = currentLeft - pixelsPerFrame * progress;
        } else {
          newPos = currentLeft + pixelsPerFrame * progress;
        }
        
        ul.style.left = `${newPos}px`;
        
        if (progress < 1) {
          ul.animationId = window.requestAnimationFrame(step);
        } else {
          self.conveyorAnimate(ul, newDirection);
        }
      }
      
      ul.animationId = window.requestAnimationFrame(step);
    },
    
    pauseAnim: function(ul) {
      if (!ul && this.elements) {
        const elementsArray = Array.from(this.elements);
        for (let i = 0; i < elementsArray.length; i++) {
          const listEl = elementsArray[i].querySelector("ul");
          if (listEl && listEl.animationId) {
            window.cancelAnimationFrame(listEl.animationId);
            listEl.animationId = null;
          }
        }
        return;
      }
      
      if (ul && ul.animationId) {
        window.cancelAnimationFrame(ul.animationId);
        ul.animationId = null;
      }
    },
    
    playAnim: function() {
      const elementsArray = Array.from(this.elements);
      for (let i = 0; i < elementsArray.length; i++) {
        const ul = elementsArray[i].querySelector("ul");
        if (ul) {
          this.conveyorAnimate(ul, dirTick ? "reverse" : "normal");
        }
      }
    }
  };
  
  window.IsCodiTicker = IsCodiTicker;
  
})(window, document);